+/* Try to parse a mouse event from ibuf starting at ibuf_pos.
+ * Loads any immediately-available stdin bytes first.
+ * Returns: 1 = press (globals set, ibuf_pos advanced past seq),
+ *          2 = release (ibuf_pos advanced, globals not meaningful),
+ *          0 = no match (ibuf_pos unchanged). */
+int term_try_mouse(void)
+{
+	struct pollfd pfd = {STDIN_FILENO, POLLIN};
+	unsigned char tmp[32];
+	int n;
+	/* Load any bytes that are immediately available */
+	if (poll(&pfd, 1, 5) > 0) {
+		n = read(STDIN_FILENO, tmp, sizeof(tmp));
+		if (n > 0) {
+			if (ibuf_cnt + n >= ibuf_sz) {
+				ibuf_sz = ibuf_cnt + n + 128;
+				ibuf = erealloc(ibuf, ibuf_sz);
+			}
+			memcpy(ibuf + ibuf_cnt, tmp, n);
+			ibuf_cnt += n;
+		}
+	}
+	/* Need at least '[' next */
+	if (ibuf_pos >= ibuf_cnt || ibuf[ibuf_pos] != '[')
+		return 0;
+	/* X10 basic: ESC [ M b x y  (5 bytes total after ESC) */
+	if (ibuf_pos + 1 < ibuf_cnt && ibuf[ibuf_pos + 1] == 'M' &&
+			ibuf_pos + 4 < ibuf_cnt) {
+		int btn = ibuf[ibuf_pos + 2] - 32;
+		xmouse_col = ibuf[ibuf_pos + 3] - 32 - 1;
+		xmouse_row = ibuf[ibuf_pos + 4] - 32 - 1;
+		ibuf_pos += 5;
+		return (btn & 3) == 3 ? 2 : 1; /* 3 = button release */
+	}
+	/* SGR 1006: ESC [ < btn ; col ; row M/m */
+	if (ibuf_pos + 1 < ibuf_cnt && ibuf[ibuf_pos + 1] == '<') {
+		unsigned int i = ibuf_pos + 2;
+		int btn = 0, x = 0, y = 0;
+		while (i < ibuf_cnt && ibuf[i] >= '0' && ibuf[i] <= '9')
+			btn = btn * 10 + (ibuf[i++] - '0');
+		if (i < ibuf_cnt && ibuf[i] == ';') {
+			i++;
+			while (i < ibuf_cnt && ibuf[i] >= '0' && ibuf[i] <= '9')
+				x = x * 10 + (ibuf[i++] - '0');
+		}
+		if (i < ibuf_cnt && ibuf[i] == ';') {
+			i++;
+			while (i < ibuf_cnt && ibuf[i] >= '0' && ibuf[i] <= '9')
+				y = y * 10 + (ibuf[i++] - '0');
+		}
+		if (i < ibuf_cnt && (ibuf[i] == 'M' || ibuf[i] == 'm')) {
+			int release = (ibuf[i] == 'm');
+			ibuf_pos = i + 1;
+			if (btn == 64 || btn == 65)
+				return btn == 64 ? 3 : 4; /* 3=scroll up, 4=scroll down */
+			xmouse_col = x - 1;
+			xmouse_row = y - 1;
+			return release ? 2 : 1;
+		}
+	}
+	return 0;
+}
